#include <iostream>
#include <string>
#include <iomanip>
#include <vector>
#include <tuple>
#include <sstream>

class Date {
private:
    int day;
    int month;
    int year;

public:
    Date(int d, int m, int y) : day(d), month(m), year(y) {}

    bool isValidDate() {
        if (year <= 0) return false;
        if (month < 1 || month > 12) return false;
        if (day < 1) return false;

        if (month == 1 || month == 3 || month == 5 || month == 7 || month == 8 || month == 10 || month == 12) {
            if (day > 31) return false;
        } else if (month == 4 || month == 6 || month == 9 || month == 11) {
            if (day > 30) return false;
        } else if (month == 2) {
            bool isLeap = (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0);
            if (isLeap) {
                if (day > 29) return false;
            } else {
                if (day > 28) return false;
            }
        }
        return true;
    }

    void displayDate() {
        std::stringstream ss;
        if (day < 10) ss << '0';
        ss << day << '/';
        if (month < 10) ss << '0';
        ss << month << '/';
        ss << year;

        std::cout << ss.str();
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::vector<std::tuple<int, int, int>> inputs = {
        {15, 3, 2023},
        {29, 2, 2024},
        {29, 2, 2023},
        {31, 4, 2023},
        {31, 1, 2023},
        {1, 13, 2023},
        {1, 0, 2023},
        {0, 1, 2023},
        {29, 2, 2000},
        {29, 2, 1900},
        {1, 1, 0},
        {1, 1, -2023}
    };

    for (const auto& input_tuple : inputs) {
        int d = std::get<0>(input_tuple);
        int m = std::get<1>(input_tuple);
        int y = std::get<2>(input_tuple);

        Date date(d, m, y);
        std::cout << "Input: " << d << " " << m << " " << y << "\n";
        std::cout << "isValid: " << (date.isValidDate() ? "true" : "false") << ", display: ";
        date.displayDate();
        std::cout << "\n";
    }
    return 0;
}
